schema.sql:
-- Supabase DDL for Seefar e-commerce app

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Users table
CREATE TABLE IF NOT EXISTS public.users (
  id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  phone text,
  email text,
  name text,
  avatar text,
  "createdAt" timestamptz DEFAULT now(),
  "totalPointsEarned" integer DEFAULT 0,
  "currentPoints" integer DEFAULT 0,
  "tierLevel" text DEFAULT 'bronze',
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own profile" ON public.users
  FOR SELECT USING (auth.uid() = id);

CREATE POLICY "Users can update own profile" ON public.users
  FOR UPDATE USING (auth.uid() = id);

CREATE INDEX IF NOT EXISTS idx_users_email ON public.users(email);
CREATE INDEX IF NOT EXISTS idx_users_phone ON public.users(phone);

-- Menu items table
CREATE TABLE IF NOT EXISTS public.menu_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  description text,
  price numeric NOT NULL,
  category text,
  image text,
  available boolean DEFAULT true,
  calories integer,
  popular boolean DEFAULT false,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.menu_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Menu items are viewable by all" ON public.menu_items
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_menu_items_category ON public.menu_items(category);
CREATE INDEX IF NOT EXISTS idx_menu_items_available ON public.menu_items(available);

-- Customizations table
CREATE TABLE IF NOT EXISTS public.customizations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "menuItemId" uuid NOT NULL REFERENCES public.menu_items(id) ON DELETE CASCADE,
  name text NOT NULL,
  required boolean DEFAULT false,
  "maxSelections" integer,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.customizations ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Customizations are viewable by all" ON public.customizations
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_customizations_menu_item ON public.customizations("menuItemId");

-- Customization options table
CREATE TABLE IF NOT EXISTS public.customization_options (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "customizationId" uuid NOT NULL REFERENCES public.customizations(id) ON DELETE CASCADE,
  name text NOT NULL,
  "priceModifier" numeric DEFAULT 0,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.customization_options ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Customization options are viewable by all" ON public.customization_options
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_customization_options_customization ON public.customization_options("customizationId");

-- Transactions table
CREATE TABLE IF NOT EXISTS public.transactions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  amount numeric NOT NULL,
  "pointsEarned" integer DEFAULT 0,
  "pointsRedeemed" integer DEFAULT 0,
  timestamp timestamptz DEFAULT now(),
  "receiptUrl" text,
  status text DEFAULT 'completed',
  "storeName" text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.transactions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own transactions" ON public.transactions
  FOR SELECT USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_transactions_user ON public.transactions("userId");
CREATE INDEX IF NOT EXISTS idx_transactions_timestamp ON public.transactions(timestamp);

-- Order items table
CREATE TABLE IF NOT EXISTS public.order_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "transactionId" uuid NOT NULL REFERENCES public.transactions(id) ON DELETE CASCADE,
  "menuItemId" uuid NOT NULL REFERENCES public.menu_items(id) ON DELETE RESTRICT,
  quantity integer NOT NULL,
  subtotal numeric NOT NULL,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.order_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own order items" ON public.order_items
  FOR SELECT USING (
    "transactionId" IN (
      SELECT id FROM public.transactions WHERE "userId" = auth.uid()
    )
  );

CREATE INDEX IF NOT EXISTS idx_order_items_transaction ON public.order_items("transactionId");
CREATE INDEX IF NOT EXISTS idx_order_items_menu_item ON public.order_items("menuItemId");

-- Rewards table
CREATE TABLE IF NOT EXISTS public.rewards (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  "pointsRequired" integer NOT NULL,
  description text,
  image text,
  category text,
  active boolean DEFAULT true,
  "expiryDays" integer,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.rewards ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Rewards are viewable by all" ON public.rewards
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_rewards_active ON public.rewards(active);

-- User redemptions table
CREATE TABLE IF NOT EXISTS public.user_redemptions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  "rewardId" uuid NOT NULL REFERENCES public.rewards(id) ON DELETE RESTRICT,
  "redeemedAt" timestamptz DEFAULT now(),
  "expiryDate" timestamptz,
  status text DEFAULT 'active',
  code text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.user_redemptions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own redemptions" ON public.user_redemptions
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert own redemptions" ON public.user_redemptions
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_user_redemptions_user ON public.user_redemptions("userId");
CREATE INDEX IF NOT EXISTS idx_user_redemptions_reward ON public.user_redemptions("rewardId");
CREATE INDEX IF NOT EXISTS idx_user_redemptions_status ON public.user_redemptions(status);

-- Payment methods table
CREATE TABLE IF NOT EXISTS public.payment_methods (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  type text NOT NULL,
  "last4Digits" text,
  "cardHolder" text,
  "expiryDate" text,
  "isDefault" boolean DEFAULT false,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.payment_methods ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own payment methods" ON public.payment_methods
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert own payment methods" ON public.payment_methods
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update own payment methods" ON public.payment_methods
  FOR UPDATE USING (auth.uid() = "userId");

CREATE POLICY "Users can delete own payment methods" ON public.payment_methods
  FOR DELETE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_payment_methods_user ON public.payment_methods("userId");

-- Handle new user creation from auth.users
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.users (id, email, phone, name, avatar, "createdAt", "totalPointsEarned", "currentPoints", "tierLevel", updated_at)
  VALUES (
    NEW.id,
    NEW.email,
    NEW.raw_user_meta_data ->> 'phone',
    NEW.raw_user_meta_data ->> 'name',
    NEW.raw_user_meta_data ->> 'avatar',
    now(),
    COALESCE((NEW.raw_user_meta_data ->> 'totalPointsEarned')::integer, 0),
    COALESCE((NEW.raw_user_meta_data ->> 'currentPoints')::integer, 0),
    COALESCE(NEW.raw_user_meta_data ->> 'tierLevel', 'bronze'),
    now()
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END; $$;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();
